import{av as n,o as e,c as s,aR as a}from"./chunks/framework.b_ghmPru.js";const u=JSON.parse('{"title":"CSS 之 contain 属性","description":"","frontmatter":{"title":"CSS 之 contain 属性","lang":"zh_CN"},"headers":[],"relativePath":"basic/contain.md","filePath":"basic/contain.md","lastUpdated":1708572770000}'),t={name:"basic/contain.md"},i=a(`<h2 id="css-之-contain-属性" tabindex="-1">CSS 之 <code>contain</code> 属性 <a class="header-anchor" href="#css-之-contain-属性" aria-label="Permalink to &quot;CSS 之 \`contain\` 属性&quot;">​</a></h2><p>CSS的<code>contain</code>属性允许作者指示元素及其内容尽可能‎‎独立于‎‎文档树的其余部分。这允许浏览器重新计算布局、样式、油漆、大小或它们的任何组合，以达到 DOM 的有限区域，而不是整个页面，从而产生明显的性能优势</p><p>这个属性在包含大量独立组件的页面非常实用，它可以防止某个小部件的 CSS 规则改变对页面上的其他东西造成影响。</p><div class="tip custom-block"><p class="custom-block-title">Note: If applied (with value: paint, strict or content), this property creates:</p><p>A new <a href="https://developer.mozilla.org/en-US/docs/Web/CSS/Containing_block" target="_blank" rel="noreferrer">containing block</a> (for the descendants whose position property is absolute or fixed).</p><p>A new <a href="https://developer.mozilla.org/en-US/docs/Web/CSS/CSS_Positioning/Understanding_z_index/The_stacking_context" target="_blank" rel="noreferrer">stacking context</a>.</p><p>A new <a href="https://developer.mozilla.org/en-US/docs/Web/Guide/CSS/Block_formatting_context" target="_blank" rel="noreferrer">block formatting context</a>.</p></div><h2 id="语法-syntax" tabindex="-1">语法(Syntax) <a class="header-anchor" href="#语法-syntax" aria-label="Permalink to &quot;语法(Syntax)&quot;">​</a></h2><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Keyword values */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: none;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: strict;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: content;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: size;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: layout;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: style;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: paint;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Multiple keywords */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: size paint;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: size layout paint;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* Global values */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: inherit;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: initial;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contain: unset;</span></span></code></pre></div><blockquote><p>属性值可以是一个，也可以是多个</p></blockquote><h2 id="各属性值的含义" tabindex="-1">各属性值的含义 <a class="header-anchor" href="#各属性值的含义" aria-label="Permalink to &quot;各属性值的含义&quot;">​</a></h2><p><code>none</code></p><p>表示元素将正常渲染，没有包含规则</p><p><code>strict</code></p><p>表示除了 <code>style</code> 外的所有的包含规则应用于这个元素。等价于 <code>contain: size layout paint</code>。</p><p><code>content</code></p><p>表示这个元素上有除了 <code>size</code> 和 <code>style</code> 外的所有包含规则。等价于 <code>contain: layout paint</code>。</p><p><code>size</code></p><p>表示这个元素的尺寸计算不依赖于它的子孙元素的尺寸。</p><p><code>layout</code></p><p>表示元素外部无法影响元素内部的布局，反之亦然。</p><p><code>style</code></p><details class="details custom-block"><summary>表明，对于可能对多个元素及其后代产生影响的属性，这些影响不会逃脱包含的元素。(此值在规范中标记为&quot;有风险&quot;，可能并非在任何地方都得到支持。)</summary><p>Indicates that, for properties that can have effects on more than just an element and its descendants, those effects don&#39;t escape the containing element. Note that this value is marked &quot;at-risk&quot; in the spec and may not be supported everywhere.</p></details><p><code>paint</code></p><p>表示这个元素的子孙节点不会在它边缘外显示。如果一个元素在视窗外或因其他原因导致不可见，则同样保证它的子孙节点不会被显示。</p><p>Indicates that descendants of the element don&#39;t display outside its bounds. If the containing box is offscreen, the browser does not need to paint its contained elements — these must also be offscreen as they are contained completely by that box. And if a descendant overflows the containing element&#39;s bounds, then that descendant will be clipped to the containing element&#39;s border-box.</p>`,23),o=[i];function c(p,l,d,r,h,k){return e(),s("div",null,o)}const y=n(t,[["render",c]]);export{u as __pageData,y as default};
